#include <bits/stdc++.h>
using namespace std;

vector<int> e[100005];
queue<int> q;
bool vis[100005];

void dfs(int x)
{
	if(vis[x]) return;
	cout << x << ' ';
	vis[x] = 1;
	for(int v : e[x])
		dfs(v);
}

void bfs(int st)
{
	q.push(st);
	while(!q.empty())
	{
		int u = q.front();
		q.pop();
		if(vis[u]) continue;
		vis[u] = 1;
		cout << u << ' ';
		for(int v : e[u])
			q.push(v);
	}
}
int main()
{
	int n, m, cnt = 0;
	cin >> n >> m;
	for(int i = 1; i <= m; i++)
	{
		int x, y;
		cin >> x >> y;
		e[x].push_back(y);
	}
	for(int i = 1; i <= n; i++)
		sort(e[i].begin(), e[i].end());
	dfs(1);
	cout << endl;
	memset(vis, 0, sizeof vis);
	bfs(1);
	return 0;
}
